#include <bits/stdc++.h>
using namespace std;

int dfs(vector<vector<int>>& grid, int i, int j) {
    int n = grid.size(), m = grid[0].size();
    if (i < 0 || i >= n || j < 0 || j >= m || grid[i][j] == 0) return 0;
    grid[i][j] = 0; // visited
    int area = 1;
    area += dfs(grid, i + 1, j);
    area += dfs(grid, i - 1, j);
    area += dfs(grid, i, j + 1);
    area += dfs(grid, i, j - 1);
    return area;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N, M; cin >> N >> M;
        vector<vector<int>> grid(N, vector<int>(M));
        for (int i = 0; i < N; ++i)
            for (int j = 0; j < M; ++j)
                cin >> grid[i][j];
        int maxArea = 0;
        for (int i = 0; i < N; ++i)
            for (int j = 0; j < M; ++j)
                if (grid[i][j] == 1) {
                    int area = dfs(grid, i, j);
                    maxArea = max(maxArea, area);
                }
        cout << maxArea << '\n';
    }
    return 0;
}

