  if (i < 0 || i >= n || j < 0 || j >= m || grid[i][j] === 0) return 0;
  grid[i][j] = 0;
  let area = 1;
  area += dfs(grid, i + 1, j, n, m);
  area += dfs(grid, i - 1, j, n, m);
  area += dfs(grid, i, j + 1, n, m);
  area += dfs(grid, i, j - 1, n, m);
  return area;
}
